import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Save, Calendar, ShoppingBag, Hash, Receipt, CreditCard, User, Lock, Wallet } from 'lucide-react';

const Lancamento = () => {
  const [cartoes, setCartoes] = useState([]);
  const [usuarios, setUsuarios] = useState([]); 
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);

  // Lista organizada de A-Z
  const formasPagamento = [
    "Boleto", "Crédito", "Débito", "Dinheiro", "Pix", "Transferência"
  ].sort();

  const [form, setForm] = useState({
    descricao: '', 
    valor_total: '', 
    loja: '', 
    pedido: '', 
    nota_fiscal: '', 
    user_id: '', 
    forma_pagamento: 'Crédito', // Padrão Crédito
    parcelado: false, 
    num_parcelas: 1, 
    cartao: '', 
    data_compra: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    verificarAcessoEBucarDados();
  }, []);

  async function verificarAcessoEBucarDados() {
    try {
      setFetching(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfil } = await supabase
        .from('profiles')
        .select('tipo_usuario')
        .eq('id', user.id)
        .single();

      setPerfilLogado(perfil);

      if (perfil?.tipo_usuario === 'proprietario') {
        const { data: dataCartoes } = await supabase
          .from('cartoes')
          .select('id, nome')
          .order('nome', { ascending: true });
        setCartoes(dataCartoes || []);

        const { data: dataUsers } = await supabase
          .from('profiles')
          .select('id, nome')
          .order('nome', { ascending: true });
        setUsuarios(dataUsers || []);
      }
    } catch (err) {
      console.error("Erro ao carregar dados:", err);
    } finally {
      setFetching(false);
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    if (parseFloat(form.valor_total) <= 0) {
      alert("O valor deve ser maior que zero!");
      setLoading(false);
      return;
    }

    if (!form.user_id) {
      alert("Por favor, selecione o responsável pelo gasto.");
      setLoading(false);
      return;
    }

    const isCredito = form.forma_pagamento === 'Crédito';

    if (isCredito && !form.cartao) {
      alert("Por favor, selecione o cartão utilizado.");
      setLoading(false);
      return;
    }

    const numParcelasFinal = isCredito ? parseInt(form.num_parcelas) : 1;

    const { error } = await supabase
      .from('compras')
      .insert([{
        ...form,
        valor_total: parseFloat(form.valor_total),
        num_parcelas: numParcelasFinal,
        parcelado: numParcelasFinal > 1,
        cartao: isCredito ? form.cartao : 'À Vista'
      }]);

    if (error) {
      alert("Erro ao salvar: " + error.message);
    } else {
      alert("✅ Gasto registrado com sucesso!");
      setForm({
        descricao: '', valor_total: '', loja: '', pedido: '', 
        nota_fiscal: '', user_id: '', forma_pagamento: 'Crédito',
        parcelado: false, num_parcelas: 1, cartao: '', 
        data_compra: new Date().toISOString().split('T')[0]
      });
    }
    setLoading(false);
  };

  if (fetching) return <div style={{ padding: '40px', textAlign: 'center' }}>Carregando permissões...</div>;
  
  if (perfilLogado?.tipo_usuario !== 'proprietario') {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '60vh', gap: '20px' }}>
        <div style={{ background: '#fff1f2', padding: '20px', borderRadius: '50%', color: '#f43f5e' }}><Lock size={48} /></div>
        <h2 style={{ color: '#0f172a' }}>Acesso Restrito</h2>
        <p style={{ color: '#64748b', textAlign: 'center', maxWidth: '300px' }}>
          Apenas usuários <b>Proprietários</b> podem realizar novos lançamentos de gastos.
        </p>
      </div>
    );
  }

  const labelStyle = { 
    display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.75rem', 
    fontWeight: '700', color: '#64748b', marginBottom: '8px', textTransform: 'uppercase'
  };

  return (
    <div className="fade-in" style={{ maxWidth: '800px', margin: '0 auto', paddingBottom: '50px' }}>
      <header style={{ marginBottom: '30px' }}>
        <h2 style={{ fontSize: '1.8rem', fontWeight: 800, color: '#0f172a' }}>Novo Lançamento</h2>
        <p style={{ color: '#64748b' }}>Registre um gasto para qualquer membro da unidade</p>
      </header>
      
      <div className="card" style={{ background: '#fff', padding: '30px', borderRadius: '24px', boxShadow: '0 10px 25px rgba(0,0,0,0.03)', border: '1px solid #f1f5f9' }}>
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '25px' }}>
          
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
            <div className="input-group">
              <label style={labelStyle}><Calendar size={14} /> Data da Compra</label>
              <input type="date" className="form-control" value={form.data_compra} required onChange={e => setForm({...form, data_compra: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><ShoppingBag size={14} /> Loja / Estabelecimento</label>
              <input placeholder="Ex: Amazon" className="form-control" value={form.loja} onChange={e => setForm({...form, loja: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><User size={14} /> Responsável</label>
              <select className="form-control" required value={form.user_id} onChange={e => setForm({...form, user_id: e.target.value})} style={{ cursor: 'pointer', fontWeight: '600' }}>
                <option value="">Selecione o membro...</option>
                {usuarios.map(u => (<option key={u.id} value={u.id}>{u.nome}</option>))}
              </select>
            </div>
          </div>

          <div className="input-group">
            <label style={labelStyle}>Descrição do Item</label>
            <input placeholder="O que foi comprado?" className="form-control" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px'}}>
            <div className="input-group">
              <label style={labelStyle}><Hash size={14} /> Nº do Pedido</label>
              <input placeholder="Opcional" className="form-control" value={form.pedido} onChange={e => setForm({...form, pedido: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><Receipt size={14} /> Chave da Nota Fiscal</label>
              <input placeholder="Opcional" className="form-control" value={form.nota_fiscal} onChange={e => setForm({...form, nota_fiscal: e.target.value})} />
            </div>
          </div>

          <div style={{ 
              display: 'grid', 
              gridTemplateColumns: form.forma_pagamento === 'Crédito' ? '1.2fr 1.2fr 1fr 1fr' : '1fr 1fr', 
              gap: '15px', 
              alignItems: 'end' 
          }}>
            <div className="input-group">
              <label style={labelStyle}>Valor Total</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '15px', top: '50%', transform: 'translateY(-50%)', fontWeight: '700', color: '#94a3b8' }}>R$</span>
                <input 
                  type="number" step="0.01" placeholder="0,00" 
                  className="form-control" required value={form.valor_total} 
                  onChange={e => setForm({...form, valor_total: e.target.value})} 
                  style={{ paddingLeft: '45px' }}
                />
              </div>
            </div>

            <div className="input-group">
              <label style={labelStyle}><Wallet size={14} /> Forma de Pagamento</label>
              <select 
                className="form-control" 
                value={form.forma_pagamento} 
                onChange={e => setForm({...form, forma_pagamento: e.target.value})}
                style={{ fontWeight: '700', color: '#4361ee', background: '#f0f4ff', borderColor: '#dbeafe' }}
              >
                {formasPagamento.map(f => <option key={f} value={f}>{f}</option>)}
              </select>
            </div>

            {form.forma_pagamento === 'Crédito' && (
              <>
                <div className="input-group animate-in">
                  <label style={labelStyle}><CreditCard size={14} /> Cartão</label>
                  <select 
                    className="form-control" required value={form.cartao}
                    onChange={e => setForm({...form, cartao: e.target.value})}
                    style={{ borderColor: '#4361ee', fontWeight: '600' }}
                  >
                    <option value="">Qual?</option>
                    {cartoes.map(c => (<option key={c.id} value={c.nome}>{c.nome}</option>))}
                  </select>
                </div>

                <div className="input-group animate-in">
                  <label style={labelStyle}>Parcelas</label>
                  <input 
                    type="number" min="1" className="form-control" required 
                    value={form.num_parcelas} onChange={e => setForm({...form, num_parcelas: e.target.value})} 
                    style={{ borderColor: '#4361ee', fontWeight: '800', textAlign: 'center' }}
                  />
                </div>
              </>
            )}
          </div>

          <button 
            type="submit" 
            className="btn-primary" 
            disabled={loading}
            style={{ 
                height: '58px', marginTop: '15px', borderRadius: '16px',
                background: '#4361ee', fontSize: '1rem', fontWeight: '700',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                boxShadow: '0 10px 20px rgba(67, 97, 238, 0.2)'
            }}
          >
            {loading ? 'Processando...' : <><Save size={20} style={{ marginRight: '10px' }} /> Confirmar Lançamento</>}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Lancamento;
